"""Tests for model_training.merging — TIES and DARE merge strategies."""

import sys
from types import ModuleType
from unittest.mock import MagicMock

import pytest

_TORCH_AVAILABLE = "torch" in sys.modules or not (
    __import__("importlib").util.find_spec("torch") is None
)

requires_torch = pytest.mark.skipif(
    not _TORCH_AVAILABLE, reason="torch not installed"
)


def _inject_fake_torch() -> ModuleType:
    """Inject a minimal fake torch module for testing merge logic."""
    import numpy as np

    fake_torch = ModuleType("torch")

    class FakeTensor:
        def __init__(self, data):
            self._data = np.array(data, dtype=np.float32)
            self.dtype = np.float32
            self.shape = self._data.shape

        def float(self):
            return FakeTensor(self._data.astype(np.float32))

        def abs(self):
            return FakeTensor(np.abs(self._data))

        def flatten(self):
            return FakeTensor(self._data.flatten())

        def numel(self):
            return self._data.size

        def __mul__(self, other):
            if isinstance(other, FakeTensor):
                return FakeTensor(self._data * other._data)
            return FakeTensor(self._data * other)

        def __rmul__(self, other):
            return self.__mul__(other)

        def __truediv__(self, other):
            if isinstance(other, FakeTensor):
                return FakeTensor(self._data / other._data)
            return FakeTensor(self._data / other)

        def __ge__(self, other):
            if isinstance(other, FakeTensor):
                return FakeTensor(self._data >= other._data)
            return FakeTensor(self._data >= other)

        def __eq__(self, other):
            if isinstance(other, FakeTensor):
                return FakeTensor(self._data == other._data)
            return FakeTensor(self._data == other)

        def sum(self, dim=None):
            if dim is not None:
                return FakeTensor(np.sum(self._data, axis=dim))
            return FakeTensor(np.array(np.sum(self._data)))

        def mean(self, dim=None):
            if dim is not None:
                return FakeTensor(np.mean(self._data, axis=dim))
            return FakeTensor(np.array(np.mean(self._data)))

        def clamp(self, min=None, max=None):
            return FakeTensor(np.clip(self._data, min, max))

        def unsqueeze(self, dim):
            return FakeTensor(np.expand_dims(self._data, axis=dim))

        def to(self, dtype):
            return FakeTensor(self._data)

        def __getitem__(self, idx):
            return FakeTensor(self._data[idx])

        def __setitem__(self, idx, value):
            if isinstance(value, FakeTensor):
                self._data[idx] = value._data
            else:
                self._data[idx] = value

        @property
        def values(self):
            return FakeTensor(self._data)

    def _fake_tensor(data):
        return FakeTensor(data)

    def _stack(tensors):
        arrays = [t._data for t in tensors]
        return FakeTensor(np.stack(arrays))

    def _sign(t):
        return FakeTensor(np.sign(t._data))

    def _topk(t, k):
        flat = t._data.flatten()
        indices = np.argpartition(flat, -k)[-k:]
        values = np.sort(flat[indices])[::-1]
        result = MagicMock()
        result.values = FakeTensor(values)
        result.__getitem__ = lambda self, idx: FakeTensor(np.array(values[idx]))
        return result

    def _rand_like(t):
        return FakeTensor(np.random.rand(*t._data.shape).astype(np.float32))

    fake_torch.Tensor = FakeTensor
    fake_torch.stack = _stack
    fake_torch.sign = _sign
    fake_torch.topk = _topk
    fake_torch.rand_like = _rand_like

    sys.modules.setdefault("torch", fake_torch)
    return fake_torch


@pytest.fixture(autouse=True)
def _ensure_torch_or_fake():
    if not _TORCH_AVAILABLE:
        _inject_fake_torch()
    yield
    # Clean up fake torch if we injected it
    if not _TORCH_AVAILABLE and "torch" in sys.modules:
        fake = sys.modules.get("torch")
        if fake and isinstance(fake, ModuleType) and not hasattr(fake, "__file__"):
            del sys.modules["torch"]


@requires_torch
def test_ties_merge_preserves_shapes() -> None:
    import torch

